python3 -c "
import json
with open('/tmp/benzene_view.json') as f:
    data = json.load(f)
sections = data['Record']['Section']
def find_section(secs, name):
    for s in secs:
        if s.get('TOCHeading') == name:
            return s
        if 'Section' in s:
            r = find_section(s['Section'], name)
            if r: return r
    return None

fa = find_section(sections, 'Food Additives')
if fa:
    print(json.dumps(fa, indent=2)[:3000])
else:
    print('Not found')
